mapper.select:
SELECT al.id ,al.adjuster_name ,al.submit_time ,al.crmw_name ,al.crmw_scode ,al.security_short_name ,al.security_code ,al.adjust_type ,al.adjust_mode ,al.target_pool_id ,p.pool_name AS target_pool_name ,al.audit_status FROM ip_adjust_log al LEFT JOIN ip_investment_pool p ON p.id = al.target_pool_id AND p.is_deleted = 0
al.is_deleted = 0 AND al.pool_type = 'crmw'
AND al.crmw_scode LIKE CONCAT('%', #{crmwScode}, '%')
AND al.crmw_name LIKE CONCAT('%', #{crmwName}, '%')
AND al.submit_time >= #{adjustTimeStart}
AND al.submit_time <= CONCAT(#{adjustTimeEnd}, ' 23:59:59')
AND al.adjuster_name LIKE CONCAT('%', #{adjusterName}, '%')
AND al.adjust_mode = #{adjustMode}
AND al.audit_status = #{auditStatus}
ORDER BY al.submit_time DESC ,al.id DESC
